// 浮动品牌组件
interface FloatingBrandProps {
  className?: string;
}

export default function BrandLogos({ className = '' }: FloatingBrandProps) {
  // 品牌图标数据
  const brands = [
    {
      component: <VisaLogo className="w-16 h-10" />,
      position: { top: '15%', left: '80%' },
      animation: {
        x: [0, 5, -5, 0],
        y: [0, -5, 5, 0],
        rotate: [-2, 0, -4, -2],
      },
      duration: 8,
      delay: 0,
    },
    {
      component: <MastercardLogo className="w-16 h-10" />,
      position: { top: '80%', left: '25%' },
      animation: {
        x: [0, -5, 5, 0],
        y: [0, 5, -5, 0],
        rotate: [2, 4, 0, 2],
      },
      duration: 9,
      delay: 1.5,
    },
    {
      component: <ApplePayLogo className="w-16 h-10" />,
      position: { top: '20%', left: '25%' },
      animation: {
        x: [0, -5, 5, 0],
        y: [0, -5, 5, 0],
        rotate: [-1, 1, -3, -1],
      },
      duration: 7,
      delay: 0.5,
    },
    {
      component: <PayPalLogo className="w-16 h-10" />,
      position: { top: '30%', left: '15%' },
      animation: {
        x: [0, -5, 5, 0],
        y: [0, 5, -5, 0],
        rotate: [1, 3, -1, 1],
      },
      duration: 10,
      delay: 1,
    },
    {
      component: <AmazonLogo className="w-20 h-10" />,
      position: { top: '70%', left: '75%' },
      animation: {
        x: [0, 5, -5, 0],
        y: [0, 5, -5, 0],
        rotate: [0, 2, -2, 0],
      },
      duration: 8.5,
      delay: 2,
    },
  ];

  return (
    <div className={`absolute inset-0 pointer-events-none overflow-hidden ${className}`}>
      {brands.map((brand, index) => (
        <motion.div
          key={index}
          className="absolute filter drop-shadow-lg"
          style={{
            ...brand.position,
            transform: 'translate(-50%, -50%)',
          }}
          animate={brand.animation}
          transition={{
            duration: brand.duration,
            ease: "easeInOut",
            repeat: Infinity,
            repeatType: "loop",
            delay: brand.delay,
          }}
        >
          <div className="bg-white rounded-md shadow-lg p-2 border border-gray-200">
            {brand.component}
          </div>
        </motion.div>
      ))}
    </div>
  );
}